import java.io.*;
import java.net.*;
import java.util.*;

public class SecurityUpdater {
    public static void main(String[] args) {
        // सुरक्षा सॉफ़्टवेयर और अपडेट के लिए URL
        String url = "https://example.com/security-software.zip";

        // डिवाइसों की सूची
        List<String> devices = new ArrayList<>();
        devices.add("Device1");
        devices.add("Device2");
        devices.add("Device3");

        // सुरक्षा सॉफ़्टवेयर और अपडेट को डिवाइसों पर फैलाना
        for (String device : devices) {
            System.out.println("फैलाने के लिए डिवाइस: " + device);
            downloadAndInstall(device, url);
        }
    }

    public static void downloadAndInstall(String device, String url) {
        try {
            // डिवाइस से कनेक्ट करने के लिए Socket
            Socket socket = new Socket(device, 8080);

            // सुरक्षा सॉफ़्टवेयर और अपडेट को डाउनलोड करने के लिए URLConnection
            URLConnection connection = new URL(url).openConnection();
            InputStream inputStream = connection.getInputStream();
            OutputStream outputStream = socket.getOutputStream();

            // सुरक्षा सॉफ़्टवेयर और अपडेट को डाउनलोड और इंस्टॉल करना
            byte[] buffer = new byte[1024];
            int bytesRead;
            while ((bytesRead = inputStream.read(buffer))!= -1) {
                outputStream.write(buffer, 0, bytesRead);
            }
            outputStream.close();
            inputStream.close();

            System.out.println("सुरक्षा सॉफ़्टवेयर और अपडेट सफलतापूर्वक डाउनलोड और इंस्टॉल किया गया है: " + device);
        } catch (Exception e) {
            System.out.println("फैलाने में असफल: " + device);
            e.printStackTrace();
        }
    }
}
